#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m, x1, y1, x2, y2, x3, y3;
        scanf("%d %d %d %d %d %d %d %d", &n, &m, &x1, &y1, &x2, &y2, &x3, &y3);
        if (x1 > n || x2 > n || x3 > n || y1 > m || y2 > m || y3 > m) {
            printf("NO\n");
        } else if ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) != 0) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

